// Fix the mime type so the Compression node recognizes it as a zip
const buffer = await this.helpers.getBinaryDataBuffer(0, 'resumesZip');
const binaryData = await this.helpers.prepareBinaryData(buffer, 'resumes.zip', 'application/zip');

return [{
  json: $input.first().json,
  binary: { resumesZip: binaryData }
}];

const items = $input.all();
const results = [];

for (let i = 0; i < items.length; i++) {
  const item = items[i];
  const binaryKeys = Object.keys(item.binary || {});

  for (const key of binaryKeys) {
    const binaryData = item.binary[key];
    const fileName = binaryData.fileName || '';

    if (!fileName.endsWith('.txt')) continue;
    if (fileName.startsWith('.')) continue;
    if (fileName.includes('__MACOSX')) continue;

    try {
      const buffer = await this.helpers.getBinaryDataBuffer(i, key);
      const text = buffer.toString('utf-8');

      if (text && text.trim().length > 50) {
        results.push({
          json: {
            fileName: fileName,
            extractedText: text.trim()
          }
        });
      }
    } catch(e) {}
  }
}

return results;

const item = $input.first().json;
const resumeText = item.extractedText || '';
const fileName = item.fileName || '';
const projectId = $('Webhook').first().json.body?.projectId || '';

// Fetch rubric from Supabase (cached after first call)
const staticData = $getWorkflowStaticData('global');
if (!staticData.rubric) {
  const rubricResponse = await this.helpers.httpRequest({
    method: 'GET',
    url: 'https://thpfsrysnbvijfackpsg.supabase.co/rest/v1/rubrics?project_id=eq.' + projectId + '&order=sort_order.asc',
    headers: {
      'apikey': 'YOUR_SUPABASE_ANON_KEY',
      'Authorization': 'Bearer YOUR_SUPABASE_ANON_KEY'
    }
  });
  staticData.rubric = rubricResponse;

  await this.helpers.httpRequest({
    method: 'PATCH',
    url: 'https://thpfsrysnbvijfackpsg.supabase.co/rest/v1/projects?id=eq.' + projectId,
    headers: {
      'apikey': 'YOUR_SUPABASE_ANON_KEY',
      'Authorization': 'Bearer YOUR_SUPABASE_ANON_KEY',
      'Content-Type': 'application/json',
      'Prefer': 'return=representation'
    },
    body: JSON.stringify({ status: 'screening' })
  });
}

const rubricItems = staticData.rubric;

// Build rubric text with scoring anchors
const rubricText = rubricItems.map(r => {
  let text = `### ${r.criterion} (weight: ${r.weight}, max score: ${r.max_score})\n`;
  text += `Description: ${r.description}\n`;
  if (r.scoring_guide) {
    const sg = typeof r.scoring_guide === 'string' ? JSON.parse(r.scoring_guide) : r.scoring_guide;
    if (sg.high) text += `- High (${Math.round(r.max_score * 0.8)}–${r.max_score}): ${sg.high}\n`;
    if (sg.mid)  text += `- Mid (${Math.round(r.max_score * 0.4)}–${Math.round(r.max_score * 0.7)}): ${sg.mid}\n`;
    if (sg.low)  text += `- Low (0–${Math.round(r.max_score * 0.3)}): ${sg.low}\n`;
  }
  return text;
}).join('\n');

const systemPrompt = `<Role>
You are an expert talent evaluator with 15+ years of experience screening resumes for competitive roles. You give consistent, evidence-based scores grounded in what the resume actually says — not assumptions.
</Role>

<Instruction>
Score the resume against each rubric criterion using the scoring anchors as your guide. For every criterion, find a direct quote or paraphrase from the resume that justifies your score. If evidence is absent, score low.
</Instruction>

<Guardrails>
- Never invent or infer experience not stated in the resume
- Apply scoring anchors consistently — do not round up out of generosity
- Extract contact info exactly as written; use null if not present
- Output ONLY the JSON object — no preamble, no explanation outside the JSON
</Guardrails>`;

const userContent = `<Task>
Score this resume against the rubric below. Follow these steps:

1. Read the full resume once before scoring anything
2. For each criterion, find the strongest supporting evidence in the resume
3. Match that evidence to the scoring anchor (high/mid/low) to pick your score
4. Write a short evidence quote (max 20 words) directly from the resume
5. Compute total_score = sum of (score × weight) for all criteria
6. Write a 2-sentence summary: first sentence on biggest strength, second on biggest gap
</Task>

<Rubric>
${rubricText}
</Rubric>

<Resume>
${resumeText}
</Resume>

Respond ONLY with this exact JSON — no other text:
{
  "candidate_name": "Full Name or null",
  "email": "email@example.com or null",
  "phone": "phone number or null",
  "linkedin": "LinkedIn URL or null",
  "criteria_scores": [
    {
      "criterion": "criterion name",
      "score": 8,
      "max_score": 10,
      "weight": 0.2,
      "evidence": "direct quote or paraphrase from resume"
    }
  ],
  "total_score": 74.5,
  "summary": "Strongest aspect sentence. Biggest gap sentence.",
  "confidence": "high | medium | low"
}`;

return [{
  json: {
    projectId,
    fileName,
    requestBody: {
      model: 'claude-haiku-4-5-20251001',
      max_tokens: 1500,
      system: systemPrompt,
      messages: [{ role: 'user', content: userContent }]
    }
  }
}];

const response = $input.first().json;
const buildData = $('Build Scoring Request').first().json;
const projectId = buildData.projectId;
const fileName = buildData.fileName;

let content = '';
if (response.content && Array.isArray(response.content)) {
  content = response.content.map(c => c.text || '').join('');
} else if (typeof response.content === 'string') {
  content = response.content;
}

// Extract JSON — try fences first, then raw object
let jsonStr = '';
const fenceMatch = content.match(/```(?:json)?\s*\n?([\s\S]*?)\n?\s*```/);
if (fenceMatch) {
  jsonStr = fenceMatch[1].trim();
} else {
  // ✅ Updated regex to match new schema (looks for criteria_scores or total_score)
const jsonMatch = content.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    jsonStr = jsonMatch[0].trim();
  } else {
    jsonStr = content.trim();
  }
}

let parsed = {};
try {
  parsed = JSON.parse(jsonStr);
} catch(e) {
  parsed = {
    candidate_name: fileName.replace('.txt', '').replace(/_/g, ' '),
    email: null,
    phone: null,
    linkedin: null,
    criteria_scores: [],
    total_score: 0,
    summary: 'Failed to parse AI response: ' + e.message,
    confidence: 'low'
  };
}

// ✅ Fallback: compute total_score from criteria_scores if model omitted it
let totalScore = parsed.total_score || 0;
if (!totalScore && parsed.criteria_scores && parsed.criteria_scores.length > 0) {
  totalScore = parsed.criteria_scores.reduce((sum, c) => sum + (c.score * c.weight), 0);
  totalScore = Math.round(totalScore * 10) / 10;
}

return [{
  json: {
    project_id: projectId,
    source_filename: fileName,
    candidate_name: parsed.candidate_name || fileName.replace('.txt', ''),
    email: parsed.email || null,
    phone: parsed.phone || null,
    linkedin: parsed.linkedin || null,
    criteria_scores: parsed.criteria_scores || [],   // ✅ NEW
    score: totalScore,
    reasoning: parsed.summary || '',                  // reuses existing column
    confidence: parsed.confidence || 'medium',        // ✅ NEW
    status: 'pending'
  }
}];
